-- ============================================================
-- Improvements batch:
--   1. Rename ASE -> ASIAN, append "PVT. LTD." to both names
--   5. Replace Asian Seeds logo with transparent-background version
-- ============================================================

-- 1. Rename company codes and full names
update companies
set code = 'ASIAN',
    name = 'ASIAN SEEDS PVT. LTD.'
where code = 'ASE';

update companies
set name = 'ASN AGRI GENETIC PVT. LTD.'
where code = 'ASN';

-- 5. Replace the Asian Seeds logo with the new transparent PNG
update companies
set logo_url = 'data:image/png;base64,'
where code = 'ASIAN';

-- Verify
select code, name, length(logo_url) as logo_size_chars, next_dc_number
from companies
order by code;
